## Navigation Pattern
```typescript
// navigation/AppNavigator.tsx
import { NavigationContainer } from '@react-navigation/native';
import { createNativeStackNavigator } from '@react-navigation/native-stack';

const Stack = createNativeStackNavigator<RootStackParamList>();

export function AppNavigator() {
  const { user } = useAuth();

  return (
    <NavigationContainer>
      <Stack.Navigator>
        {user ? (
          <Stack.Screen name="Main" component={MainNavigator} />
        ) : (
          <Stack.Screen name="Auth" component={AuthNavigator} />
        )}
      </Stack.Navigator>
    </NavigationContainer>
  );
}
```

## State Management with Zustand
```typescript
import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';
import AsyncStorage from '@react-native-async-storage/async-storage';

export const useAppStore = create(
  persist(
    (set) => ({
      theme: 'light',
      setTheme: (theme) => set({ theme }),
    }),
    {
      name: 'app-storage',
      storage: createJSONStorage(() => AsyncStorage),
    }
  )
);
```

# React Native Debugging Guide

## Metro Bundler Issues

### Problem
`Unable to resolve module` or bundle errors.

### Solutions
```bash
# Clear cache and restart
npx react-native start --reset-cache

# Clear watchman
watchman watch-del-all

# Clean and reinstall
rm -rf node_modules
rm -rf ios/Pods
npm install
cd ios && pod install && cd ..

# For Android
cd android && ./gradlew clean && cd ..
```

## Performance Issues

```typescript
// BAD: Inline functions cause re-renders
<FlatList
  data={items}
  renderItem={({ item }) => <Item item={item} />}  // New fn each render!
/>

// GOOD: Stable function reference
const renderItem = useCallback(
  ({ item }) => <Item item={item} />,
  []
);
<FlatList data={items} renderItem={renderItem} />

// BAD: Missing keys
{items.map(item => <Item item={item} />)}  // No key!

// GOOD: Always use keys
{items.map(item => <Item key={item.id} item={item} />)}

// Optimize FlatList
<FlatList
  data={items}
  keyExtractor={(item) => item.id}
  renderItem={renderItem}
  removeClippedSubviews={true}
  maxToRenderPerBatch={10}
  windowSize={5}
  getItemLayout={(data, index) => ({
    length: ITEM_HEIGHT,
    offset: ITEM_HEIGHT * index,
    index,
  })}
/>
```

## Native Module Errors

```bash
# iOS: Pod not linked
cd ios && pod install

# Android: Module not linked (RN < 0.60)
npx react-native link package-name

# Clean native builds
# iOS
cd ios && rm -rf build && pod install

# Android
cd android && ./gradlew clean
```

